import { useState, useEffect, useRef, useCallback } from "react";

// ─── Google Fonts ────────────────────────────────────────────────────────────
const fontLink = document.createElement("link");
fontLink.rel = "stylesheet";
fontLink.href =
  "https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400&family=Great+Vibes&family=Cinzel:wght@400;500;700&family=Lateef:wght@400;700&family=EB+Garamond:ital,wght@0,400;1,400&display=swap";
document.head.appendChild(fontLink);

// ─── Embedded images (transparent bg) ───────────────────────────────────────
const IMG_COUPLE_WALK  = "data:image/png;base64,";
const IMG_COUPLE_RING  = "data:image/png;base64,";
const IMG_DANCERS      = "data:image/png;base64,";
const IMG_DHOL         = "data:image/png;base64,";

// ─── Confetti loader ─────────────────────────────────────────────────────────
let confettiLoaded = false;
let confettiFn = null;
function loadConfetti() {
  if (confettiLoaded) return Promise.resolve(confettiFn);
  return new Promise((res) => {
    const s = document.createElement("script");
    s.src = "https://cdn.jsdelivr.net/npm/canvas-confetti@1.6.0/dist/confetti.browser.min.js";
    s.onload = () => { confettiLoaded = true; confettiFn = window.confetti; res(confettiFn); };
    document.head.appendChild(s);
  });
}

// ─── Styles ──────────────────────────────────────────────────────────────────
const STYLE = `
  @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400&family=Great+Vibes&family=Cinzel:wght@400;500;700&family=Lateef:wght@400;700&family=EB+Garamond:ital,wght@0,400;1,400&display=swap');

  :root {
    --gold: #c9a84c; --gold-light: #e8cc7a; --gold-dark: #8a6914;
    --maroon: #4a0010; --maroon-mid: #6b0015; --maroon-light: #8c1a2e;
    --cream: #fdf8f0; --cream-dark: #f2ead8;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; -webkit-tap-highlight-color: transparent; }
  html, body { width: 100%; min-height: 100%; scroll-behavior: smooth; }
  body { background: var(--cream); font-family: "Cinzel", serif; color: #1a0a0a; overflow-x: hidden; }
  #root { width: 100%; min-height: 100vh; margin: 0; padding: 0; max-width: none; }

  /* ── Hero ── */
  .hero { height: 100vh; width: 100%; position: relative; overflow: hidden;
    background: radial-gradient(ellipse at center, #f9f3e2 0%, #ede3c6 60%, #d8c99a 100%);
    display: flex; align-items: center; justify-content: center; }
  .hero-bg-ring { position:absolute; border-radius:50%; pointer-events:none; }

  .hero-inner { position:absolute; inset:0; display:flex; flex-direction:column;
    align-items:center; justify-content:center; text-align:center; z-index:3; padding:20px;
    transition: opacity 1.4s ease 1s, transform 1.4s ease 1s; }
  .hero-inner.hidden  { opacity:0; transform:scale(0.95); }
  .hero-inner.visible { opacity:1; transform:scale(1); }

  .bismillah { font-family:"Lateef",cursive; font-size:clamp(2.2rem,7vw,4rem);
    color:var(--maroon); line-height:1.2; filter:drop-shadow(0 2px 6px rgba(74,0,16,.2)); }
  .hero-tagline { letter-spacing:6px; font-size:clamp(.55rem,1.5vw,.8rem); color:var(--gold-dark);
    margin:14px 0 4px; text-transform:uppercase; }
  .hero-names { font-family:"Great Vibes",cursive; font-size:clamp(3.5rem,14vw,8rem);
    color:var(--maroon); line-height:1; text-shadow:0 2px 20px rgba(74,0,16,.15); }
  .hero-amp { font-family:"Great Vibes",cursive; font-size:clamp(2rem,7vw,4.5rem);
    color:var(--gold); margin:0 10px; }
  .hero-divider { display:flex; align-items:center; gap:14px; margin:18px 0; width:min(400px,80vw); }
  .hero-divider-line { flex:1; height:1px;
    background:linear-gradient(90deg,transparent,var(--gold),transparent); }
  .hero-verse { font-family:"EB Garamond",serif; font-style:italic;
    font-size:clamp(.8rem,2vw,1rem); color:var(--maroon-light);
    max-width:380px; opacity:.85; line-height:1.7; }
  .hero-badge { margin-top:28px; border:1px solid var(--gold); padding:12px 36px;
    letter-spacing:5px; font-size:clamp(.6rem,1.6vw,.82rem); color:var(--maroon);
    background:rgba(255,255,255,.5); backdrop-filter:blur(4px); }

  /* couple image */
  .hero-couple-img { position:absolute; bottom:0; right:clamp(0px,3vw,60px); z-index:2;
    pointer-events:none; width:clamp(160px,22vw,280px);
    filter:drop-shadow(0 10px 28px rgba(74,0,16,.22));
    transition: opacity 1.8s ease 1.2s, transform 1.8s ease 1.2s; }
  .hero-couple-img.hidden  { opacity:0; transform:translateY(40px); }
  .hero-couple-img.visible { opacity:.22; transform:translateY(0); animation:heroFloat 5s ease-in-out 3s infinite; }
  @keyframes heroFloat { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-10px)} }

  /* ── Pelmet ── */
  .pelmet { position:absolute; top:0; left:0; width:100%;
    height:clamp(70px,10vw,110px); z-index:160; overflow:hidden;
    background:linear-gradient(180deg,var(--maroon) 0%,var(--maroon-mid) 60%,var(--maroon-light) 100%);
    box-shadow:0 8px 30px rgba(0,0,0,.5);
    display:flex; align-items:center; justify-content:center; }
  .pelmet-text { font-family:"Great Vibes",cursive; font-size:clamp(1.2rem,3vw,2rem);
    letter-spacing:3px; background:linear-gradient(90deg,var(--gold-dark),var(--gold-light),var(--gold-dark),var(--gold-light));
    background-size:200% auto; -webkit-background-clip:text; -webkit-text-fill-color:transparent;
    background-clip:text; animation:shimmer 3s linear infinite; position:relative; z-index:2; }
  @keyframes shimmer { 0%{background-position:-200% 0} 100%{background-position:200% 0} }
  .pelmet-scallop { position:absolute; bottom:-22px; left:0; width:100%; z-index:162; pointer-events:none; }
  .pelmet-fringe { position:absolute; bottom:-18px; left:0; width:100%;
    display:flex; justify-content:space-around; z-index:165; padding:0 5px; pointer-events:none; }
  .pelmet-fringe-strand { width:3px; height:20px;
    background:linear-gradient(180deg,#c9a84c,#f7e0a1,rgba(201,168,76,0)); border-radius:0 0 2px 2px; }

  /* ── Rope & tassel ── */
  .rope-tie { position:absolute; top:0; left:50%; transform:translateX(-50%); z-index:200;
    display:flex; flex-direction:column; align-items:center; pointer-events:none;
    transition:opacity .6s ease 2s; }
  .rope-tie.gone { opacity:0; }
  .rope-line { width:4px; height:60px;
    background:linear-gradient(180deg,#c9a84c,#f0d878,#c9a84c,#8a6914);
    border-radius:2px; box-shadow:0 0 6px rgba(201,168,76,.6); }
  .rope-tassel { width:38px; height:38px; cursor:pointer; pointer-events:all; position:relative;
    background:radial-gradient(circle at 35% 35%,#f7e0a1,#c9a84c 50%,#8a6914 100%);
    border-radius:50%; box-shadow:0 4px 12px rgba(0,0,0,.3), inset 0 -3px 6px rgba(0,0,0,.2);
    display:flex; align-items:center; justify-content:center; font-size:1rem;
    animation:tassleFloat 2.5s ease-in-out infinite; }
  .rope-tassel::after { content:""; position:absolute; inset:3px; border-radius:50%;
    background:radial-gradient(circle at 30% 30%,rgba(255,255,255,.5),transparent 60%); }
  @keyframes tassleFloat { 0%,100%{transform:translateY(0) rotate(-3deg)} 50%{transform:translateY(8px) rotate(3deg)} }
  .rope-fringe { display:flex; gap:3px; margin-top:3px; }
  .rope-fringe span { width:3px; background:linear-gradient(180deg,#c9a84c,#f0d878,transparent);
    border-radius:0 0 2px 2px; animation:fringeSwing 1.8s ease-in-out infinite; }
  @keyframes fringeSwing { 0%,100%{transform:rotate(-4deg)} 50%{transform:rotate(4deg)} }

  /* ── Curtains ── */
  .curtain-panel { position:absolute; top:0; width:51%; height:100%; overflow:hidden;
    cursor:pointer; transition:transform 2.4s cubic-bezier(.77,0,.175,1); }
  .curtain-left  { left:0;  transform-origin:left center; }
  .curtain-right { right:0; transform-origin:right center; }
  .curtain-left.open  { transform:translateX(-88%) skewY(2deg); }
  .curtain-right.open { transform:translateX(88%) skewY(-2deg); }
  .curtain-left::after,.curtain-right::before { content:""; position:absolute; top:0;
    width:6px; height:100%; z-index:10; box-shadow:0 0 16px rgba(201,168,76,.6);
    background:linear-gradient(90deg,var(--gold-dark),var(--gold-light),var(--gold-dark)); }
  .curtain-left::after  { right:0; }
  .curtain-right::before { left:0; }
  .curtain-panel svg { position:absolute; top:0; left:0; width:100%; height:100%; }

  /* ── Rosette ── */
  .rosette { position:absolute; left:50%; z-index:170; cursor:pointer;
    transform:translateX(-50%); border-radius:50%;
    background:radial-gradient(circle at 40% 35%,#f7e0a1,#c9a84c 45%,#8a6914 80%);
    box-shadow:0 4px 20px rgba(0,0,0,.4),inset 0 -4px 8px rgba(0,0,0,.2);
    display:flex; align-items:center; justify-content:center;
    transition:opacity .8s ease 1.6s, transform .8s ease 1.6s; }
  .rosette::after { content:""; position:absolute; inset:5px; border-radius:50%;
    border:1px solid rgba(255,255,255,.4); }
  .rosette.gone { opacity:0; transform:translateX(-50%) scale(0); pointer-events:none; }
  .rosette-text { font-family:"Great Vibes",cursive; color:var(--maroon);
    font-size:clamp(.8rem,2vw,1.2rem); text-shadow:0 1px 2px rgba(255,255,255,.5); position:relative; z-index:1; }

  /* ── CTA ── */
  .curtain-cta { position:absolute; bottom:36px; left:50%; transform:translateX(-50%);
    z-index:200; display:flex; flex-direction:column; align-items:center; gap:8px;
    pointer-events:none; animation:fadeInUp 1s ease .5s both; transition:opacity .5s; }
  .curtain-cta.gone { opacity:0; }
  .curtain-cta span { letter-spacing:6px; font-size:.65rem; color:#fff;
    text-shadow:0 1px 4px rgba(0,0,0,.6); font-family:"Cinzel",serif; }
  .cta-arrow { width:20px; height:20px; border-right:2px solid rgba(255,255,255,.8);
    border-bottom:2px solid rgba(255,255,255,.8); transform:rotate(45deg);
    animation:bounceDown 1.4s ease-in-out infinite; }
  @keyframes bounceDown { 0%,100%{transform:rotate(45deg) translateY(0);opacity:1} 50%{transform:rotate(45deg) translateY(6px);opacity:.5} }
  @keyframes fadeInUp { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }

  /* ── Petal ── */
  .petal { position:fixed; pointer-events:none; z-index:9999; font-size:1.2rem;
    animation:petalFall linear forwards; }
  @keyframes petalFall { 0%{transform:translateY(-20px) rotate(0deg);opacity:1} 100%{transform:translateY(100vh) rotate(720deg);opacity:0} }

  /* ── Sections ── */
  .section { min-height:100vh; padding:100px 20px; max-width:960px; margin:0 auto;
    display:flex; flex-direction:column; align-items:center; justify-content:center;
    text-align:center; position:relative; }
  .section-full { min-height:100vh; padding:100px 20px; width:100%; max-width:none;
    display:flex; flex-direction:column; align-items:center; justify-content:center;
    text-align:center; position:relative; }
  .section-label { letter-spacing:8px; font-size:clamp(.55rem,1.4vw,.72rem);
    color:var(--gold-dark); margin-bottom:10px; text-transform:uppercase; }
  .section-title { font-family:"Cormorant Garamond",serif; font-size:clamp(2rem,6vw,3.5rem);
    font-weight:300; color:var(--maroon); line-height:1.2; }
  .gold-rule { width:100%; max-width:460px; height:1px; position:relative; margin:28px auto;
    background:linear-gradient(90deg,transparent,var(--gold),transparent); }
  .gold-rule::before { content:"✦"; position:absolute; top:50%; left:50%;
    transform:translate(-50%,-50%); font-size:1rem; color:var(--gold);
    background:var(--cream); padding:0 10px; }

  /* ── Scratch ── */
  .scratch-row { width:100%; overflow-x:auto; padding:30px 0 10px; scrollbar-width:none; }
  .scratch-row::-webkit-scrollbar { display:none; }
  .scratch-group { display:flex; justify-content:center; align-items:center;
    gap:clamp(14px,3vw,40px); min-width:min-content; margin:0 auto; }
  .scratch-box { position:relative; flex:0 0 clamp(100px,22vw,160px); height:clamp(100px,22vw,160px);
    border-radius:50%; cursor:pointer; filter:drop-shadow(0 8px 20px rgba(74,0,16,.2));
    transition:transform .2s ease; }
  .scratch-box:hover { transform:scale(1.04); }
  .scratch-box canvas { position:absolute; top:0; left:0; width:100%; height:100%;
    z-index:5; border-radius:50%; transition:opacity 1.2s ease, transform 1s ease; }
  .scratch-box.cleared canvas { opacity:0; transform:scale(1.5); pointer-events:none; }
  .reveal-data { width:100%; height:100%; background:linear-gradient(135deg,#fff,#fdf8f0);
    border:2px solid var(--gold); border-radius:50%; display:flex; flex-direction:column;
    justify-content:center; align-items:center; box-shadow:inset 0 0 20px rgba(201,168,76,.1); }
  .reveal-data b { font-size:clamp(1.4rem,5vw,2.6rem); color:var(--maroon);
    font-family:"Cormorant Garamond",serif; font-weight:600; line-height:1; }
  .reveal-data small { font-size:clamp(.5rem,1.3vw,.65rem); letter-spacing:3px;
    color:var(--gold-dark); margin-top:4px; }

  /* ── Venue ── */
  .venue-section { background:linear-gradient(180deg,var(--cream-dark),var(--cream)); }
  .venue-frame { position:relative; width:min(700px,92vw); margin:40px auto; }
  .venue-frame::before,.venue-frame::after { content:""; position:absolute; border:2px solid var(--gold);
    z-index:1; pointer-events:none; border-radius:4px; }
  .venue-frame::before { inset:-12px; }
  .venue-frame::after  { inset:-20px; opacity:.4; }
  .venue-frame iframe { width:100%; display:block; border-radius:2px; filter:sepia(.12) contrast(1.04); border:0; }
  .venue-corner { position:absolute; width:30px; height:30px; border-color:var(--gold); border-style:solid; z-index:2; }
  .venue-corner.tl { top:-22px;    left:-22px;   border-width:3px 0 0 3px; }
  .venue-corner.tr { top:-22px;    right:-22px;  border-width:3px 3px 0 0; }
  .venue-corner.bl { bottom:-22px; left:-22px;   border-width:0 0 3px 3px; }
  .venue-corner.br { bottom:-22px; right:-22px;  border-width:0 3px 3px 0; }
  .venue-dir-btn { display:inline-block; margin-top:16px; padding:10px 32px;
    border:1px solid var(--gold); color:var(--gold-dark); font-size:.65rem; letter-spacing:4px;
    text-decoration:none; font-family:"Cinzel",serif; transition:background .3s,color .3s; cursor:pointer; background:transparent; }
  .venue-dir-btn:hover { background:var(--gold); color:var(--maroon); }

  /* ── Flip cards ── */
  .ceremonies-grid { display:flex; flex-wrap:wrap; justify-content:center; gap:30px;
    margin-top:50px; perspective:1000px; }
  .flip-card { width:clamp(220px,28vw,280px); height:clamp(260px,35vw,320px);
    perspective:1000px; cursor:pointer; }
  .flip-inner { position:relative; width:100%; height:100%;
    transform-style:preserve-3d; transition:transform .8s cubic-bezier(.4,0,.2,1); }
  .flip-card:hover .flip-inner,
  .flip-card.flipped .flip-inner { transform:rotateY(180deg); }
  .flip-face { position:absolute; inset:0; backface-visibility:hidden; border-radius:8px;
    display:flex; flex-direction:column; align-items:center; justify-content:center; padding:30px 20px; }
  .flip-front { background:linear-gradient(145deg,var(--maroon),var(--maroon-mid) 50%,var(--maroon));
    box-shadow:0 20px 50px rgba(74,0,16,.35),inset 0 1px 0 rgba(255,255,255,.1);
    border:1px solid rgba(201,168,76,.3); position:relative; }
  .flip-front::before { content:""; position:absolute; inset:8px; border:1px solid rgba(201,168,76,.25);
    border-radius:4px; pointer-events:none; }
  .flip-back { background:linear-gradient(145deg,#fdf8f0,#f7efd8); transform:rotateY(180deg);
    box-shadow:0 20px 50px rgba(74,0,16,.2); border:1px solid var(--gold); }
  .ceremony-name { font-family:"Great Vibes",cursive; font-size:clamp(2rem,5vw,2.8rem);
    color:var(--gold-light); text-shadow:0 0 30px rgba(201,168,76,.4); margin-bottom:8px; }
  .ceremony-icon { font-size:clamp(2rem,4vw,2.5rem); margin-bottom:10px; }
  .ceremony-hint { font-size:clamp(.55rem,1.2vw,.65rem); letter-spacing:4px;
    color:rgba(255,255,255,.5); margin-top:14px; }
  .ceremony-back-name { font-family:"Cinzel",serif; font-size:clamp(.9rem,2.5vw,1.2rem);
    letter-spacing:4px; color:var(--maroon); margin-bottom:16px; }
  .ceremony-back-detail { font-family:"EB Garamond",serif; font-size:clamp(.9rem,2.5vw,1.1rem);
    color:var(--maroon-light); line-height:1.8; }
  .ceremony-back-detail strong { display:block; font-family:"Cormorant Garamond",serif;
    font-size:clamp(1.4rem,4vw,1.8rem); color:var(--maroon); font-weight:400; }

  /* ── Timeline ── */
  .timeline-wrap { position:relative; width:min(600px,90vw); margin-top:50px; }
  .timeline-wrap::before { content:""; position:absolute; left:50%; top:0; bottom:0; width:1px;
    background:linear-gradient(180deg,transparent,var(--gold) 10%,var(--gold) 90%,transparent);
    transform:translateX(-50%); }
  .tl-item { display:flex; align-items:center; gap:20px; margin:30px 0; }
  .tl-item.even { flex-direction:row-reverse; }
  .tl-content { flex:1; text-align:right; padding-right:20px; }
  .tl-item.even .tl-content { text-align:left; padding-right:0; padding-left:20px; }
  .tl-dot { flex:0 0 16px; height:16px; border-radius:50%; background:var(--gold);
    box-shadow:0 0 0 4px rgba(201,168,76,.3),0 0 12px rgba(201,168,76,.5); }
  .tl-title { font-family:"Cinzel",serif; font-size:clamp(.75rem,2vw,.95rem);
    letter-spacing:3px; color:var(--maroon); }
  .tl-time { font-family:"EB Garamond",serif; font-size:clamp(.9rem,2.5vw,1.1rem);
    color:var(--gold-dark); font-style:italic; }

  /* ── RSVP ── */
  .rsvp-section { background:linear-gradient(160deg,var(--maroon) 0%,#2a0008 100%); color:#fff; }
  .rsvp-section .section-label { color:rgba(201,168,76,.6); }
  .rsvp-section .section-title { color:var(--gold-light); }
  .rsvp-bg { position:absolute; inset:0; pointer-events:none;
    background:radial-gradient(circle at 20% 20%,rgba(201,168,76,.08),transparent 50%),
               radial-gradient(circle at 80% 80%,rgba(201,168,76,.08),transparent 50%); }
  .rsvp-arabic { font-family:"Lateef",cursive; font-size:clamp(4rem,12vw,8rem);
    color:rgba(201,168,76,.12); position:absolute; top:50%; left:50%;
    transform:translate(-50%,-50%); pointer-events:none; white-space:nowrap; }
  .rsvp-inner { position:relative; z-index:2; display:flex; flex-direction:column;
    align-items:center; text-align:center; }
  .rsvp-divider { width:min(400px,80vw); height:1px; margin:28px auto;
    background:linear-gradient(90deg,transparent,rgba(201,168,76,.5),transparent); }
  .rsvp-verse { font-family:"EB Garamond",serif; font-size:clamp(1rem,2.5vw,1.2rem);
    color:rgba(255,255,255,.6); font-style:italic; max-width:400px; line-height:1.8; }
  .rsvp-btn { margin-top:40px; padding:16px 52px; border:1px solid var(--gold);
    color:var(--gold-light); font-family:"Cinzel",serif; font-size:clamp(.65rem,1.8vw,.85rem);
    letter-spacing:6px; text-transform:uppercase; position:relative; overflow:hidden;
    cursor:pointer; background:transparent; transition:color .4s ease; }
  .rsvp-btn::before { content:""; position:absolute; inset:0; background:var(--gold);
    transform:scaleX(0); transform-origin:left; transition:transform .4s ease; z-index:-1; }
  .rsvp-btn:hover::before { transform:scaleX(1); }
  .rsvp-btn:hover { color:var(--maroon); }
  .rsvp-small { margin-top:24px; font-size:.62rem; letter-spacing:3px; color:rgba(201,168,76,.4); }

  /* ── Section deco images ── */
  .sec-deco { position:absolute; pointer-events:none; z-index:0; }
  .sec-deco-left  { left:clamp(-10px,1vw,30px); bottom:clamp(40px,8vw,100px);
    width:clamp(120px,18vw,220px); filter:drop-shadow(0 8px 20px rgba(74,0,16,.15)); }
  .sec-deco-right { right:clamp(-10px,1vw,30px); bottom:clamp(40px,8vw,100px);
    width:clamp(120px,18vw,220px); filter:drop-shadow(0 8px 20px rgba(74,0,16,.15)); }
  @media(max-width:500px){ .sec-deco{display:none;} }

  /* ── Footer ── */
  footer { background:#0e0306; color:rgba(255,255,255,.5); padding:80px 20px 50px; text-align:center; }
  .footer-logo { font-family:"Great Vibes",cursive; font-size:clamp(3rem,8vw,5rem);
    color:var(--gold); line-height:1; margin-bottom:16px; }
  .footer-sub { letter-spacing:6px; font-size:.6rem; color:rgba(201,168,76,.5); margin-bottom:40px; }
  .footer-line { width:1px; height:40px;
    background:linear-gradient(180deg,var(--gold),transparent); margin:0 auto 20px; }
  .footer-tiny { font-size:.6rem; letter-spacing:3px; color:rgba(255,255,255,.2); }

  /* ── WhatsApp ── */
  .wa-float { position:fixed; bottom:30px; right:28px; z-index:9000;
    display:flex; align-items:center; gap:10px;
    background:linear-gradient(135deg,#25d366,#128c7e); color:#fff;
    text-decoration:none; padding:13px 20px 13px 14px; border-radius:50px;
    box-shadow:0 6px 24px rgba(37,211,102,.45),0 2px 8px rgba(0,0,0,.2);
    font-family:"Cinzel",serif; font-size:.65rem; letter-spacing:2px;
    transition:transform .25s ease,box-shadow .25s ease; overflow:hidden; }
  .wa-float:hover { transform:translateY(-3px) scale(1.04); box-shadow:0 12px 32px rgba(37,211,102,.55); }
  .wa-icon { width:26px; height:26px; flex-shrink:0; }
  .wa-pulse { position:absolute; inset:0; border-radius:50px;
    border:2px solid rgba(255,255,255,.5); animation:waPulse 2s ease-out infinite; pointer-events:none; }
  @keyframes waPulse { 0%{transform:scale(1);opacity:.7} 70%{transform:scale(1.12);opacity:0} 100%{transform:scale(1.12);opacity:0} }

  /* ── Scroll reveal ── */
  .reveal { transition: opacity .9s ease, transform .9s ease; }
  .reveal.hidden  { opacity:0; transform:translateY(50px); }
  .reveal.visible { opacity:1; transform:translateY(0); }
  .tl-reveal.hidden  { opacity:0; }
  .tl-reveal.odd.hidden  { transform:translateX(-30px); }
  .tl-reveal.even.hidden { transform:translateX(30px); }
  .tl-reveal.visible { opacity:1; transform:translateX(0); transition:opacity .8s ease, transform .8s ease; }

  @media(max-width:480px){
    .ceremonies-grid{gap:16px;}
    .flip-card{width:280px;height:300px;}
  }
`;

// ─── inject styles ────────────────────────────────────────────────────────────
const styleEl = document.createElement("style");
styleEl.textContent = STYLE;
document.head.appendChild(styleEl);

// ─── Force full-screen: override Vite/CRA default #root constraints ───────────
const resetEl = document.createElement("style");
resetEl.textContent = `
  html, body, #root {
    width: 100% !important;
    max-width: none !important;
    min-height: 100vh !important;
    margin: 0 !important;
    padding: 0 !important;
    overflow-x: hidden !important;
  }
`;
document.head.appendChild(resetEl);

// ─── useInView hook ───────────────────────────────────────────────────────────
function useInView(threshold = 0.15) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    if (!ref.current) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold }
    );
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, visible];
}

// ─── Scratch canvas component ─────────────────────────────────────────────────
function ScratchCircle({ label, value }) {
  const canvasRef = useRef(null);
  const boxRef = useRef(null);
  const [cleared, setCleared] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    const box = boxRef.current;
    if (!canvas || !box) return;
    canvas.width = box.offsetWidth;
    canvas.height = box.offsetHeight;
    const ctx = canvas.getContext("2d");
    const g = ctx.createLinearGradient(0, 0, canvas.width, canvas.height);
    g.addColorStop(0, "#8a6914");
    g.addColorStop(0.3, "#f7e0a1");
    g.addColorStop(0.6, "#c9a84c");
    g.addColorStop(1, "#a67c00");
    ctx.fillStyle = g;
    ctx.beginPath();
    ctx.arc(canvas.width / 2, canvas.height / 2, canvas.width / 2, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = "rgba(255,255,255,0.25)";
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.arc(canvas.width / 2, canvas.height / 2, canvas.width / 2 - 8, 0, Math.PI * 2);
    ctx.stroke();
    ctx.fillStyle = "rgba(74,0,16,0.7)";
    ctx.font = `bold ${canvas.width * 0.13}px Cinzel`;
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillText("REVEAL", canvas.width / 2, canvas.height / 2);
  }, []);

  const handleClick = useCallback(async () => {
    if (cleared) return;
    setCleared(true);
    const cfg = await loadConfetti();
    if (!cfg || !boxRef.current) return;
    const rect = boxRef.current.getBoundingClientRect();
    cfg({
      particleCount: 60, spread: 80,
      origin: { x: (rect.left + rect.width / 2) / window.innerWidth, y: (rect.top + rect.height / 2) / window.innerHeight },
      colors: ["#c9a84c", "#ffb7c5", "#f7e0a1", "#ffffff"],
    });
  }, [cleared]);

  return (
    <div ref={boxRef} className={`scratch-box${cleared ? " cleared" : ""}`} onClick={handleClick}>
      <div className="reveal-data">
        <small>{label}</small>
        <b>{value}</b>
      </div>
      <canvas ref={canvasRef} className="scratch-canvas" />
    </div>
  );
}

// ─── Flip card ────────────────────────────────────────────────────────────────
function FlipCard({ icon, name, backName, date, day, time, mood }) {
  const [flipped, setFlipped] = useState(false);
  return (
    <div className={`flip-card${flipped ? " flipped" : ""}`} onClick={() => setFlipped(!flipped)}>
      <div className="flip-inner">
        <div className="flip-face flip-front">
          <div className="ceremony-icon">{icon}</div>
          <div className="ceremony-name">{name}</div>
          <div className="ceremony-hint">TAP TO REVEAL</div>
        </div>
        <div className="flip-face flip-back">
          <div className="ceremony-back-name">{backName}</div>
          <div className="ceremony-back-detail">
            <strong>{date}</strong>
            {day}<br />{time}<br /><br />{mood}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Section reveal wrapper ───────────────────────────────────────────────────
function RevealSection({ children, className = "", style = {} }) {
  const [ref, visible] = useInView(0.1);
  return (
    <div ref={ref} className={`reveal ${visible ? "visible" : "hidden"} ${className}`} style={style}>
      {children}
    </div>
  );
}

// ─── Timeline item ────────────────────────────────────────────────────────────
function TlItem({ title, time, even }) {
  const [ref, visible] = useInView(0.2);
  return (
    <div ref={ref} className={`tl-item${even ? " even" : ""} tl-reveal ${even ? "even" : "odd"} ${visible ? "visible" : "hidden"}`}>
      {even ? (
        <>
          <div style={{ flex: 1 }} />
          <div className="tl-dot" />
          <div className="tl-content">
            <div className="tl-title">{title}</div>
            <div className="tl-time">{time}</div>
          </div>
        </>
      ) : (
        <>
          <div className="tl-content">
            <div className="tl-title">{title}</div>
            <div className="tl-time">{time}</div>
          </div>
          <div className="tl-dot" />
          <div style={{ flex: 1 }} />
        </>
      )}
    </div>
  );
}

